// Get both inputs from merge node
const analysisInput = $input.all().find(input => input.json.analysis);
const prFilesInput = $input.all().find(input => Array.isArray(input.json));

const analysisData = analysisInput ? analysisInput.json.analysis : null;
const fileType = analysisInput ? analysisInput.json.fileType : 'json';
const prFiles = prFilesInput ? prFilesInput.json : [];

// Create the teacher comparison prompt
let comparisonPrompt = `You are a senior code reviewer acting as a teacher. `;

if (fileType === 'json') {
  comparisonPrompt += `Compare the pull request changes with the original code analysis.

**ORIGINAL ANALYSIS FOR: ${analysisData.filename}**
- Score: ${analysisData.score}/100
- Metrics: ${JSON.stringify(analysisData.metrics, null, 2)}
- Summary: ${analysisData.summary}`;
} else {
  comparisonPrompt += `Compare the pull request changes against the original reference file.

**REFERENCE FILE: ${analysisData.filename}**
- Content Type: ${analysisData.isCode ? 'Code File' : 'Text File'}`;
}

comparisonPrompt += `\n\n**PULL REQUEST CHANGES TO REVIEW:**\n`;

let diffs = '';
let addedFiles = [];
let modifiedFiles = [];

for (const file of prFiles) {
  // Categorize files by their status
  if (file.status === 'added') {
    addedFiles.push(file);
  } else if (file.status === 'modified') {
    modifiedFiles.push(file);
  }

  diffs += `### File: ${file.filename} [${file.status.toUpperCase()}]\n`;

  // Highlight if this is the file matching our analysis/reference
  if (fileType === 'json' && file.filename === analysisData.filename.replace('-analysis.json', '')) {
    diffs += "⭐ **MAIN FILE - COMPARE AGAINST ANALYSIS** ⭐\n";
  } else if (fileType !== 'json' && file.filename === analysisData.filename) {
    diffs += "⭐ **REFERENCE FILE - COMPARE CHANGES** ⭐\n";
  }

  if (file.patch) {
    const safePatch = file.patch.replace(/```/g, "''");
    diffs += "```diff\n" + safePatch + "\n```\n";
  } else {
    diffs += "_No patch available (likely binary file)_\n";
  }
  diffs += "\n---\n";
}

comparisonPrompt += diffs;

// Add reference content if it's not JSON analysis
if (fileType !== 'json') {
  comparisonPrompt += `\n**REFERENCE FILE CONTENT:**\n\`\`\`\n${analysisData.content}\n\`\`\`\n`;
}

// Add special instructions based on file types
comparisonPrompt += `

**REVIEW STRATEGY BY FILE TYPE:**

${addedFiles.length > 0 ? `**NEW FILES (${addedFiles.length} added):**
- Review the ENTIRE file content as this is brand new code
- Check if it follows project patterns and standards
- Verify it integrates well with existing codebase
- Ensure it meets quality benchmarks from the beginning\n` : ''}

${modifiedFiles.length > 0 ? `**MODIFIED FILES (${modifiedFiles.length} changed):**
- Focus on the CHANGES (diff) shown in the patch
- Evaluate if changes are improvements or regressions
- Check if changes maintain/exceed original quality standards
- Verify the changes solve the intended problem effectively\n` : ''}

**REVIEW INSTRUCTIONS:**
1. Compare PR changes against ${fileType === 'json' ? 'original analysis standards' : 'reference file content'}
2. ${fileType === 'json' ? `Check if changes maintain or improve quality score (${analysisData.score})` : 'Verify changes align with reference implementation'}
3. ${fileType === 'json' ? 'Verify metrics are preserved: complexity, maintainability, security, etc.' : 'Ensure code quality and best practices are maintained'}
4. Provide specific, actionable feedback
5. Suggest improvements if quality might decrease
6. Focus on the main file first

**FOR ADDED FILES:**
- Treat as completely new code submission
- Review entire structure, patterns, and architecture
- Check if it meets all quality metrics from start
- Provide comprehensive feedback on the whole implementation

**FOR MODIFIED FILES:**
- Focus on the specific changes made
- Evaluate the quality of the modifications
- Check if changes introduce new issues or fix existing ones
- Assess if the changes are minimal and focused

**YOUR MISSION:**
- Review the proposed code changes file by file and by significant modification
- Generate inline comments on the relevant lines of code
- Ignore files without patches
- Do not repeat the code snippet or the filename
- Write the comments directly, without introducing the context
- Act as a teacher providing constructive feedback

**OUTPUT FORMAT:**
- Start with overall assessment
- Then provide file-by-file comments (separate added vs modified files)
- End with specific recommendations
- Use clear, constructive language
`;

return [
  {
    json: {
      user_message: comparisonPrompt.trim(),
      analysis_present: fileType === 'json',
      reference_file: fileType !== 'json' ? analysisData.filename : null,
      pr_files_count: prFiles.length,
      added_files_count: addedFiles.length,
      modified_files_count: modifiedFiles.length,
      added_files: addedFiles.map(f => f.filename),
      modified_files: modifiedFiles.map(f => f.filename)
    }
  }
];

const { Buffer } = require('buffer');
const originalFile = $input.first();

try {
  const decodedContent = Buffer.from(originalFile.json.content, 'base64').toString('utf8');

  // Detect if it's JSON or code/text
  let analysisData;
  let fileType = 'unknown';

  try {
    // Try to parse as JSON first
    analysisData = JSON.parse(decodedContent);
    fileType = 'json';
  } catch (jsonError) {
    // If not JSON, treat as text/code
    analysisData = {
      content: decodedContent,
      filename: originalFile.json.name,
      isCode: true
    };
    fileType = 'text';
  }

  return [
    {
      json: {
        analysis: analysisData,
        originalFile: originalFile.json,
        fileType: fileType,
        success: true
      }
    }
  ];

} catch (error) {
  return [
    {
      json: {
        error: Error,
        success: false
      }
    }
  ];
}

